import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o as n,c as d,a as i,b as e,d as l,e as a}from"./app-ab825736.js";const c={},m=a('<h1 id="vscode" tabindex="-1"><a class="header-anchor" href="#vscode" aria-hidden="true">#</a> VSCode</h1><div class="subtitle">——neovim 死里配，不如 vscode 同步一根毛</div><p>我是 vscode 的重度使用者，所有的编程行为 all in vscode。虽说是 electron 电子垃圾，但它确实强大且开箱即用。<em>（据说是优化得很好的电子垃圾，来源请求）</em></p><p>在 linux 端我曾尝试抛弃 vscode，转向 neovim，但是几天后即放弃。</p><h2 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h2>',5),s=i("em",null,"设置",-1),h=i("code",null,"打开设置（json）",-1),u={href:"https://github.com/lxl66566/my-key-data/blob/main/config/vscode/settings.json",target:"_blank",rel:"noopener noreferrer"},p=a('<h3 id="快捷键" tabindex="-1"><a class="header-anchor" href="#快捷键" aria-hidden="true">#</a> 快捷键</h3><p>这里是我比较常用的快捷键。</p><ul><li><code>Ctrl + ,</code>：打开设置</li><li><code>Ctrl + r</code>（资源管理器窗口）：选择打开最近项目</li><li><code>Ctrl + p</code>：选择打开文件</li><li><code>Ctrl + Shift + p</code>：操作面板</li></ul><h2 id="插件" tabindex="-1"><a class="header-anchor" href="#插件" aria-hidden="true">#</a> 插件</h2><p>插件系统是 vscode 的精髓。正由于活跃的插件系统，vscode 才能如此强大。这里会放出我使用的插件。</p><ul><li>通用： <ul><li>AI 代码补全（只需其一）：<em>Codeium...</em> | <em>Tabnine...</em></li><li>更好的警告：<em>Error Lens</em>，<em>SonarLint</em></li><li>轻量级 Git 可视化：<em>Git Graph</em></li><li>代码格式化：<em>Prettier - Code formatter</em>（主要用于 markdown</li><li>编辑器：<em>Vim</em></li></ul></li><li>markdown：<em>Markdown Preview Enhanced</em></li><li>前端：<em>Auto Rename Tag</em>，<em>Rome</em>（需要设置 <code>&quot;rome.requireConfiguration&quot;: false</code>）</li><li>C++：<em>clangd</em></li><li>python：<em>Black Formatter</em>，<em>isort</em>，<em>Ruff</em></li><li>rust：<em>Cargo</em>，<em>cargo-crate-completer</em>，<em>Even Better TOML</em>，<em>rust-analyzer</em></li><li>java：<em>Language Support for Java(TM) by Red Hat</em>，<em>Test Runner for Java</em></li><li>kotlin：<em>Kotlin Language</em>，<em>vscode-runner</em></li><li>数据库：<em>SQLite Viewer</em></li><li>其他：<em>Chinese (Simplified)...</em>，<em>CodeSnap</em></li></ul><h3 id="关于补全" tabindex="-1"><a class="header-anchor" href="#关于补全" aria-hidden="true">#</a> 关于补全</h3><p>上述两个代码补全的插件我都用过，感觉难分伯仲。目前在使用 <em>Codeium</em>。不过如果还想看看其他的 AI 代码补全插件（本人未使用过），也可以：</p>',8),f={href:"https://docs.codegpt.co/",target:"_blank",rel:"noopener noreferrer"},_={href:"https://codegeex.cn/",target:"_blank",rel:"noopener noreferrer"},v=a('<h2 id="feature" tabindex="-1"><a class="header-anchor" href="#feature" aria-hidden="true">#</a> feature</h2><p>vscode 的特色：</p><ul><li>前文的插件系统不再赘述</li><li><strong>设置同步</strong>，可以瞬间在其他平台搭好最适合自己的开发环境。（这也是小标题的由来）</li><li>集成全文搜索；linux 下需要自己 <code>find</code> / <code>grep</code></li><li>集成 git 图形化界面，虽说我不用且功能不多，但是对不会用 git 的新手非常友好</li><li>多光标支持</li></ul><h2 id="其他评价" tabindex="-1"><a class="header-anchor" href="#其他评价" aria-hidden="true">#</a> 其他评价</h2><ul><li>vscode 的可自定义程度还不够高</li><li>有一些官方插件太臃肿了（例如 <em>python</em>，<em>C/C++</em>）</li><li>没法控制插件行为和权限 <ul><li>（比如某个看似没啥用的插件向我的 C 盘写入了 6GB 的缓存，说的就是你，<em>SonarLint</em>！）</li><li>（比如 java 的插件天天申请公共网络访问权限）</li></ul></li></ul>',5);function g(C,b){const o=t("ExternalLinkIcon");return n(),d("div",null,[m,i("p",null,[e("在 "),s,e(" 页右上角可以 "),h,e("，我经常需要直接编辑配置文件。"),i("a",u,[e("这里"),l(o)]),e("是我的全局配置文件。")]),p,i("ul",null,[i("li",null,[i("a",f,[e("Code GPT"),l(o)]),e("：需要自己提供 API KEY 或本地跑模型。")]),i("li",null,[i("a",_,[e("CodeGeeX"),l(o)]),e("：国产，对标 GitHub CoPilot")])]),v])}const L=r(c,[["render",g],["__file","vscode.html.vue"]]);export{L as default};
